option.value:
param(
    [string]$KeystorePath = "C:\\UNIVERSIDAD\\TDSE\\secure-webapp-architecture-aws\\backend\\certs\\securewebapp-local.p12",
    [string]$StorePassword = "changeit",
    [string]$Alias = "securewebapp-local",
    [string]$DnsName = "localhost",
    [int]$ValidityDays = 365,
    [switch]$ForceOverwrite
)

$javaHome = $env:JAVA_HOME
if ([string]::IsNullOrWhiteSpace($javaHome)) {
    Write-Error "JAVA_HOME is not set. Please set JAVA_HOME environment variable."
    exit 1
}

$keytoolPath = Join-Path $javaHome "bin\keytool.exe"
if (-not (Test-Path $keytoolPath)) {
    Write-Error "keytool not found at $keytoolPath"
    exit 1
}

$certsDir = Split-Path -Parent $KeystorePath
if (-not (Test-Path $certsDir)) {
    New-Item -ItemType Directory -Path $certsDir -Force | Out-Null
}

if (Test-Path $KeystorePath) {
    if ($ForceOverwrite) {
        Remove-Item $KeystorePath -Force
    } else {
        Write-Error "Keystore already exists at $KeystorePath. Use -ForceOverwrite to replace it."
        exit 1
    }
}

& $keytoolPath -genkeypair `
  -alias $Alias `
  -keyalg RSA `
  -keysize 2048 `
  -storetype PKCS12 `
  -keystore $KeystorePath `
  -validity $ValidityDays `
  -storepass $StorePassword `
  -keypass $StorePassword `
  -dname "CN=$DnsName, OU=TDSE, O=ECI, L=Bogota, S=Cundinamarca, C=CO"

if ($LASTEXITCODE -eq 0) {
    Write-Host "Keystore successfully created at: $KeystorePath"
    Write-Host ""
    Write-Host "Set environment variables before running backend:"
    Write-Host "SSL_ENABLED=true"
    Write-Host "SSL_KEYSTORE_PATH=$KeystorePath"
    Write-Host "SSL_KEYSTORE_PASSWORD=$StorePassword"
    Write-Host "SSL_KEY_ALIAS=$Alias"
} else {
    Write-Error "Failed to create keystore. keytool exit code: $LASTEXITCODE"
    exit $LASTEXITCODE
}

package edu.eci.tdse.securespring.auth;

import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/api/auth")
public class AuthController {

    private final AuthService authService;

    public AuthController(AuthService authService) {
        this.authService = authService;
    }

    @PostMapping("/login")
    public ResponseEntity<LoginResponse> login(@RequestBody LoginRequest loginRequest) {
        if (loginRequest.username() == null || loginRequest.username().isBlank()
                || loginRequest.password() == null || loginRequest.password().isBlank()) {
            return ResponseEntity.badRequest().body(new LoginResponse(false, "Username and password are required."));
        }

        boolean authenticated = authService.validateCredentials(loginRequest.username(), loginRequest.password());
        if (!authenticated) {
            return ResponseEntity.status(401).body(new LoginResponse(false, "Invalid credentials."));
        }

        return ResponseEntity.ok(new LoginResponse(true, "Login successful."));
    }
}

package edu.eci.tdse.securespring.auth;

import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

@Service
public class AuthService {

    private final PasswordEncoder passwordEncoder;
    private final Map<String, String> usersByUsername = new ConcurrentHashMap<>();

    public AuthService(PasswordEncoder passwordEncoder) {
        this.passwordEncoder = passwordEncoder;
        // Demo user for commit 2. Database persistence will be added in a later commit.
        usersByUsername.put("student", passwordEncoder.encode("student123"));
    }

    public boolean validateCredentials(String username, String password) {
        String storedHash = usersByUsername.get(username);
        if (storedHash == null) {
            return false;
        }
        return passwordEncoder.matches(password, storedHash);
    }
}

package edu.eci.tdse.securespring.auth;

public record LoginRequest(String username, String password) {
}

package edu.eci.tdse.securespring.auth;

public record LoginResponse(boolean success, String message) {
}

package edu.eci.tdse.securespring.health;

import java.util.Map;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/api")
public class HealthController {

    @GetMapping("/health")
    public ResponseEntity<Map<String, String>> health() {
        return ResponseEntity.ok(Map.of("status", "ok", "service", "secure-spring-backend"));
    }
}

package edu.eci.tdse.securespring.security;

import java.util.List;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.Customizer;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.http.SessionCreationPolicy;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.web.cors.CorsConfiguration;
import org.springframework.web.cors.CorsConfigurationSource;
import org.springframework.web.cors.UrlBasedCorsConfigurationSource;

@Configuration
public class SecurityConfig {

    @Value("${APP_ALLOWED_ORIGIN:http://localhost:8080}")
    private String allowedOrigin;

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
                .cors(Customizer.withDefaults())
                .csrf(csrf -> csrf.disable())
                .sessionManagement(session -> session.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
                .authorizeHttpRequests(auth -> auth
                        .requestMatchers("/api/health", "/api/auth/login").permitAll()
                        .anyRequest().authenticated()
                )
                .httpBasic(Customizer.withDefaults());

        return http.build();
    }

    @Bean
    public PasswordEncoder passwordEncoder() {
        return new BCryptPasswordEncoder();
    }

    @Bean
    public CorsConfigurationSource corsConfigurationSource() {
        CorsConfiguration configuration = new CorsConfiguration();
        configuration.setAllowedOrigins(List.of(allowedOrigin));
        configuration.setAllowedMethods(List.of("GET", "POST", "OPTIONS"));
        configuration.setAllowedHeaders(List.of("Content-Type", "Authorization"));

        UrlBasedCorsConfigurationSource source = new UrlBasedCorsConfigurationSource();
        source.registerCorsConfiguration("/**", configuration);
        return source;
    }
}
